import{_ as e,o as i,c as s,a3 as a}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Printing & Logistics","description":"","frontmatter":{"title":"Printing & Logistics"},"headers":[],"relativePath":"en/advertisers/printing-services.md","filePath":"en/advertisers/printing-services.md"}'),r={name:"en/advertisers/printing-services.md"};function o(n,t,l,d,c,p){return i(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="printing-and-logistics-services" tabindex="-1">Printing and Logistics Services <a class="header-anchor" href="#printing-and-logistics-services" aria-label="Permalink to &quot;Printing and Logistics Services&quot;">​</a></h1><p>getinside acts as a <strong>central purchasing office</strong> to pool volumes, reduce your costs, and guarantee responsible production.</p><hr><h2 id="certified-quality" tabindex="-1">Certified Quality <a class="header-anchor" href="#certified-quality" aria-label="Permalink to &quot;Certified Quality&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><div class="gi-cert-row"><div class="gi-cert-item"><span class="gi-cert-icon">🇫🇷</span><strong>Made in France</strong><span>100% of production in French workshops.</span></div><div class="gi-cert-item"><span class="gi-cert-icon">🌱</span><strong>Eco-responsibility</strong><span>Imprim&#39;Vert Certification · Vegetable inks · FSC and PEFC paper.</span></div><div class="gi-cert-item"><span class="gi-cert-icon">✅</span><strong>ISO Standards</strong><span>ISO 9001 (Quality) and ISO 14001 (Environment).</span></div></div></div><hr><h2 id="paper-specifications" tabindex="-1">Paper Specifications <a class="header-anchor" href="#paper-specifications" aria-label="Permalink to &quot;Paper Specifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Criterion</th><th style="text-align:left;">Specification</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Formats</strong></td><td style="text-align:left;">A5 (148 × 210 mm), A6 (105 × 148 mm), Gift card</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">250 to 300 g/m²</td></tr><tr><td style="text-align:left;"><strong>Type</strong></td><td style="text-align:left;">Matte coated or semi-matte coated</td></tr><tr><td style="text-align:left;"><strong>Certification</strong></td><td style="text-align:left;">FSC or PEFC mandatory</td></tr><tr><td style="text-align:left;"><strong>Lamination</strong></td><td style="text-align:left;">❌ No — makes QR codes less readable</td></tr></tbody></table><hr><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📦 For your campaigns (Sponsored Mail)</strong><p>You book a campaign with a partner distributor. getinside prints your materials, manages assembly (e.g., fugitive glue dot for sample), and delivers directly to the distributor&#39;s warehouse.</p></div><div class="gi-value-card"><strong>🏷️ Self-promotion (For you)</strong><p>Do you want to print your own thank you cards or flyers to insert into <strong>your own parcels</strong>? Create an &quot;internal&quot; campaign via the platform and benefit from our industrial group rates. Pallet delivery to your door.</p></div></div><hr><h2 id="economic-model" tabindex="-1">Economic Model <a class="header-anchor" href="#economic-model" aria-label="Permalink to &quot;Economic Model&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💎 Transparency</strong><p>The cost is clearly displayed during campaign configuration. No surprises.</p></div><div class="gi-value-card"><strong>📦 All included</strong><p>Printing + Finishing + Transport. A single item, a single contact.</p></div><div class="gi-value-card"><strong>📉 Economies of scale</strong><p>The larger the volume, the lower the unit cost. Sliding scale rates apply from the first few thousand copies.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Just-in-time Delivery</p><p>Prints are delivered directly to distributors&#39; warehouses, synchronized to their logistics <strong>Lead Time</strong>. The merchandise arrives exactly when the partner needs it — zero unnecessary storage on your end.</p></div><hr><h2 id="disability-commitment" tabindex="-1">Disability Commitment <a class="header-anchor" href="#disability-commitment" aria-label="Permalink to &quot;Disability Commitment&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Exclusive Partnership with Adapted Enterprises (EA)</strong><p>For all manual operations (assembly, gluing samples, enveloping), we work exclusively with <strong>Adapted Enterprises</strong>, which employ at least <strong>80% workers with disabilities</strong> in their production staff.</p></div><div class="gi-value-card"><strong>Direct Social Impact</strong><p>By entrusting your logistics to getinside, you support the professional integration of people distanced from the labor market. Our partners work in particular to maintain employment in rural areas and support the skills development of their employees.</p></div></div><hr><div class="info custom-block"><p class="custom-block-title">How to order?</p><p>The print option is automatically offered to you when creating a campaign on the platform.</p><p>For a specific request (special formats, custom assembly): <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></p></div>',20)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
